class SessionStats { final Duration duration; final int bytesSent; final int bytesReceived; final double avgBitrateKbps; final int reconnects; const SessionStats({this.duration = Duration.zero, this.bytesSent = 0, this.bytesReceived = 0, this.avgBitrateKbps = 0, this.reconnects = 0}); String get formattedDuration { final h = duration.inHours.toString().padLeft(2,'0'); final m = duration.inMinutes.remainder(60).toString().padLeft(2,'0'); final s = duration.inSeconds.remainder(60).toString().padLeft(2,'0'); return duration.inHours > 0 ? '$h:$m:$s' : '$m:$s'; } }